import microcoapy
import machine

# CoAP server object
server = microcoapy.COAPServer()

# Define sensor and actuator values
temp = 25
light = 50

# GET handler for /sensors/temp resource
@server.get('/sensors/temp')
def get_temp(request):
    return microcoapy.Message(payload=str(temp))

# PUT handler for /sensors/temp resource
@server.put('/sensors/temp')
def set_temp(request):
    global temp
    temp = float(request.payload)

# GET handler for /actuators/light resource
@server.get('/actuators/light')
def get_light(request):
    return microcoapy.Message(payload=str(light))

# PUT handler for /actuators/light resource
@server.put('/actuators/light')
def set_light(request):
    global light
    light = int(request.payload)

# Run the CoAP server
server.run()